{
  "title": "Cloudflare's ML v8: Detecting Residential Proxies and Improving Bot Detection",
  "summary": "Cloudflare has introduced ML v8, a new machine learning model designed to detect residential proxies and improve bot detection. This model is part of Cloudflare's Bot Management system and is currently being tested in shadow mode. ML v8 is capable of classifying over 17 million unique IPs that participate in residential proxy attacks and has shown significant improvements in detecting previously missed attacks.",
  "key_points": {
    "model_deployment": "ML v8 is currently being tested in shadow mode and is expected to be deployed in active mode after thorough validation and monitoring.",
    "detection_capabilities": "ML v8 is capable of detecting residential proxy traffic with high accuracy, allowing Cloudflare to block malicious traffic while allowing legitimate residential users to access protected websites.",
    "improvements_in_detection": "ML v8 has shown significant improvements in detecting previously missed attacks, including a 95% classification accuracy for distributed residential proxy attacks targeting the voucher redemption endpoint and a 70% increase in detecting bots from cloud providers on zones marked as under attack.",
    "model_training": "The training of ML v8 involved the use of Catboost models, hyperparameter tuning, and the evaluation of model performance against a variety of validation datasets and specializations.",
    "features_used": "The model uses a combination of network and behavioral signals, including global features, high cardinality features, and single request features, to detect residential proxy traffic.",
    "real_world_impact": "ML v8 has already shown promising results in real-world scenarios, with the ability to detect significant spikes in bot requests from residential proxies and to identify previously missed content scraping attacks."
  },
  "related_topics": {
    "machine_learning": "Cloudflare's use of machine learning in bot detection and network security.",
    "bot_management": "Cloudflare's Bot Management system and its role in protecting websites from malicious bot traffic.",
    "network_security": "The importance of network security in protecting corporate networks and Internet-scale applications.",
    "cloudflare_services": "An overview of Cloudflare's services, including its connectivity cloud, DDoS protection, and Zero Trust security solutions."
  },
  "related_posts": {
    "related_post_1": "February 13, 2: A related post discussing Cloudflare's Bot Management and its role in protecting websites from malicious bot traffic.",
    "related_post_2": "A post discussing Cloudflare's connectivity cloud and its role in helping customers build Internet-scale applications efficiently."
  },
  "call_to_action": {
    "existing_customers": "For existing Bot Management customers, Cloudflare recommends toggling 'Auto-update machine learning model' to instantly gain the benefits of ML v8 and its residential proxy detection.",
    "non_customers": "For those not currently using Cloudflare Bot Management, Cloudflare encourages contacting their sales team to try out Bot Management."
