{
  "ai_analysis": {
    "ai_use_cases": [
      {
        "use_case": "Personalized Cart Recommendation System",
        "description": "Swiggy implemented a personalized cart recommendation system called 'Swiggy Suggests' to address the 'Paradox of Choice' and reduce the time customers take to place an order. The system uses historical order data, customer embeddings, and approximate nearest neighbor (ANN) indexing to recommend relevant food combinations.",
        "ai_techniques_used": [
          "Customer embeddings",
          "Approximate Nearest Neighbor (ANN) indexing",
          "Cross-sell modeling",
          "Vegness score imputation",
          "Ranking based on similarity, budget, and geographical proximity"
        ],
        "ai_components": [
          "Food Intelligence (FI) engine for hierarchical classification of items",
          "Cross-sell model for generating complementary item recommendations",
          "DSP (Data Science Platform) for model deployment and real-time inference",
          "ANN index using Spotify's Annoy library",
          "Ranking layer with manually tuned weights"
        ],
        "ai_benefits": [
          "Reduces time to order by addressing the paradox of choice",
          "Improves customer experience by suggesting relevant food combinations",
          "Enhances personalization through vegness score and customer embeddings",
          "Ensures diversity and freshness in recommendations"
        ]
      },
      {
        "use_case": "Rule Generation for Valid Carts",
        "description": "The system generates rules for determining valid carts based on dish family pairs, co-order metrics, and item ratings. These rules ensure that only popular and well-rated item combinations are recommended.",
        "ai_techniques_used": [
          "Dish family classification",
          "Co-order metrics analysis",
          "Item rating filtering"
        ],
        "ai_components": [
          "Food Intelligence (FI) engine for dish family classification",
          "Historical order data analysis for co-order metrics"
        ],
        "ai_benefits": [
          "Filters out incoherent or unpopular item combinations",
          "Ensures recommendations are based on real customer behavior",
          "Improves the quality and relevance of suggested carts"
        ]
      },
      {
        "use_case": "Candidate Cart Retrieval and Ranking",
        "description": "The system retrieves candidate carts from two sources: overall platform orders and customer order history. It then ranks these carts based on similarity, budget, and geographical proximity.",
        "ai_techniques_used": [
          "Approximate Nearest Neighbor (ANN) indexing",
          "Customer embedding generation",
          "Ranking based on multiple features"
        ],
        "ai_components": [
          "ANN index using Spotify's Annoy library",
          "Customer embedding generation from historical orders",
          "Ranking layer with manually tuned weights"
        ],
        "ai_benefits": [
          "Efficiently retrieves relevant cart recommendations",
          "Ensures recommendations are personalized to the customer's preferences",
          "Balances similarity, budget, and geographical proximity in rankings"
        ]
      },
      {
        "use_case": "Production Setup and Workflow Orchestration",
        "description": "The system is deployed in a production environment with two workflows: one for slower, weekly tasks and another for daily tasks. This ensures that the system remains efficient and up-to-date.",
        "ai_techniques_used": [
          "Workflow orchestration",
          "Offline job processing",
          "Real-time inference"
        ],
        "ai_components": [
          "Data Science Platform (DSP) for model deployment and real-time inference",
          "Custom wrappers for Spotify's Annoy library",
          "DynamoDB for fast-access storage of recommendations"
        ],
        "ai_benefits": [
          "Ensures scalability and efficiency in production",
          "Balances compute costs with freshness of recommendations",
          "Supports real-time inference for customer recommendations"
        ]
      }
    ],
    "ai_challenges": [
      {
        "challenge": "Lack of Labeled Data for Ranking",
        "description": "The system did not have labeled data at the cart level to build a supervised model for ranking. This required the use of a simple, manually tuned ranking logic.",
        "ai_solution": "A ranking logic was implemented that sorts carts based on a weighted average of similarity, budget, and geographical proximity."
      },
      {
        "challenge": "Geographical and Temporal Variability",
        "description": "Customer preferences and food trends vary across cities and over time, making it challenging to create a one-size-fits-all recommendation system.",
        "ai_solution": "The system uses geohash5-based indexing and weekly updates to capture seasonal trends and city-specific preferences."
      },
      {
        "challenge": "Micro-Personalization",
        "description": "Customer preferences are highly personal, making it difficult to create universally relevant recommendations.",
        "ai_solution": "A 'vegness score' was introduced to impute customer preferences at the mealslot and geohash level, ensuring that recommendations align with dietary preferences."
      },
      {
        "challenge": "Storage and Compute Costs",
        "description": "Storing and computing recommendations for all customers daily can be computationally expensive.",
        "ai_solution": "The system uses a two-workflow approach, with slower, weekly tasks and faster, daily tasks, to balance compute costs with freshness of recommendations."
      }
    ],
    "ai_future_improvements": [
      {
        "improvement": "Online Learning with Real-Time Feedback",
        "description": "Future versions of the system could incorporate online learning using Multi-Armed Bandits to adapt to customer feedback in real time.",
        "ai_benefits": [
          "Improves the accuracy of recommendations over time",
          "Enhances personalization by adapting to customer behavior in real time"
        ]
      },
      {
        "improvement": "Enhanced Feature Store with Clickstream Data",
        "description": "The feature store could be enhanced with clickstream data to improve the ranking of recommendations.",
        "ai_benefits": [
          "Provides more detailed insights into customer behavior",
          "Improves the relevance and accuracy of recommendations"
        ]
      },
      {
        "improvement": "Real-Time Nearest Neighbor Fetching",
        "description": "Instead of precomputing recommendations, the system could fetch nearest neighbor carts online and apply a real-time scorer.",
        "ai_benefits": [
          "Reduces storage and compute costs",
          "Improves the freshness and relevance of recommendations"
        ]
      },
      {
        "improvement": "Enhanced Customer Embeddings and Retrieval Algorithms",
        "description": "Future versions could improve the customer embeddings and retrieval algorithms to enhance the quality of recommendations.",
        "ai_benefits": [
          "Improves the accuracy of recommendations",
          "Enhances the diversity and freshness of suggested carts"
        ]
      }
    ]
  }
