{
  "title": "Enhancing User Experience with a GenAI-Powered Carousel System on DoorDash",
  "summary": "This paper presents the development and implementation of a GenAI-powered carousel system on DoorDash, designed to enhance user experience by delivering personalized and contextually relevant store and dish recommendations. The system leverages large language models (LLMs) to generate carousel titles, metadata, and to moderate content, ensuring that the recommendations are both engaging and compliant with DoorDash policies. The system also employs advanced retrieval and ranking techniques to ensure that the most relevant stores and dishes are displayed to users. Evaluation results show significant improvements in user engagement metrics, including click-through rates and conversion rates, demonstrating the effectiveness of the system.",
  "key_points": {
    "system_overview": {
      "objective": "To enhance user experience by delivering personalized and contextually relevant store and dish recommendations.",
      "approach": "Leverage large language models (LLMs) to generate carousel titles, metadata, and to moderate content.",
      "components": [
        "Carousel title and metadata generation using LLMs",
        "Content moderation using an LLM-as-jury approach",
        "Store and dish retrieval using KNN and GPU-based exact search",
        "Ranking and presentation of stores using a hybrid model combining engagement signals and embedding similarity"
      ]
    },
    "content_generation": {
      "carousel_titles": "Generated using LLMs with prompts tailored to user preferences, part-of-day information, and topic balancing.",
      "metadata": "Generated using LLMs to align with merchant profiles and user preferences, enhancing the relevance of store recommendations.",
      "personalization": "Metadata is derived from consumer preferences and order history, enabling personalized queries for store retrieval."
    },
    "content_moderation": {
      "approach": "LLM-as-jury approach with three different LLMs reviewing content independently and subjecting their decisions to a veto process.",
      "effectiveness": "Achieves 95% recall in detecting inappropriate or offensive carousel titles."
    },
    "store_retrieval": {
      "method": "Exact KNN search on GPU using pre-generated masks and document embeddings.",
      "benefits": "Enables low-latency online retrieval of stores and dishes, ensuring fast and accurate results."
    },
    "ranking_and_presentation": {
      "method": "Hybrid ranking model combining engagement signals and embedding similarity.",
      "formula": "FinalScore(s) = R(s)^α · S(s)^β",
      "benefits": "Balances engagement and relevance, ensuring that the most relevant and engaging stores are displayed."
    },
    "evaluation_and_results": {
      "offline_evaluations": [
        "Carousel and user relevance: Assessed by internal users based on criteria such as repetition frequency, specificity, diversity, and relevance.",
        "Carousel and store relevance: Objectively determined using third-party labelers and precision@K metric."
      ],
      "a_b_tests": {
        "submarkets": "San Francisco and Manhattan",
        "results": {
          "click_rate_improvement": "Double-digit improvement",
          "conversion_rates": "Improved",
          "homepage_relevance": "Improved",
          "merchant_discovery": "Increased exposure to more cuisines and new merchants"
        }
      }
    },
    "future_work": {
      "scope_expansion": "Plan to expand carousels into other dimensions such as affordability, speed, and non-restaurant shopping (e.g., groceries).",
      "model_enhancement": "Plan to fine-tune the LLM with DoorDash-specific insights such as co-purchase patterns, regional customer preferences, and store performance."
    }
  },
  "conclusion": "The GenAI-powered carousel system on DoorDash has demonstrated significant improvements in user engagement metrics, including click-through rates and conversion rates. The system's ability to generate personalized and contextually relevant recommendations, combined with advanced retrieval and ranking techniques, has enhanced the user experience and driven greater exploration and merchant discovery. Future work will focus on expanding the scope of the system and enhancing the LLM with DoorDash-specific insights to deliver even more precise recommendations."
}

