{
  "ai_use_case": "AI is used to detect policy-violating speech in voice chats on Roblox, ensuring a safe and civil environment for users.",
  "ai_solution": "Roblox implemented a machine learning pipeline that processes voice chat data to identify and classify policy violations such as profanity, bullying, discrimination, and other inappropriate content.",
  "ai_components": [
    {
      "component": "Machine Labeling Pipeline",
      "description": "This pipeline automatically processes voice chat data to generate training labels. It includes audio chunk splitting, audio transcription using ASR models, and text classification using an in-house text filter."
    },
    {
      "component": "Transformer-based Models",
      "description": "Roblox used Transformer-based architectures, specifically WavLM and Whisper, to develop models that can detect policy violations in voice communications with low latency."
    },
    {
      "component": "Model Optimization Techniques",
      "description": "To improve performance, Roblox employed techniques such as quantization, MFCC inputs with CNNs, and voice activity detection (VAD) to reduce inference latency and improve robustness."
    },
    {
      "component": "Distillation Setup",
      "description": "A student-teacher distillation setup was used, where a Whisper encoder served as the teacher network and a WavLM end-to-end architecture served as the student network, resulting in a more compact and faster model."
    }
  ],
  "ai_benefits": [
    "Improved detection of policy violations in voice chats, leading to a safer environment for users.",
    "Significant reduction in policy-violating behavior, with a 15.3% decrease in severe-level voice abuse reports and an 11.4% decrease in violations per minute of speech.",
    "Efficient processing of large-scale voice data, enabling real-time detection and classification of inappropriate content.",
    "Ability to scale the solution across multiple languages and handle language mixing, expanding the reach of the AI system."
  ],
  "ai_challenges": [
