      "multi_task_models": {
        "description": "DoorDash has developed multi-task models (MT models) to improve ETA prediction accuracy across various use cases. These models are trained sequentially to achieve better performance, despite the increased complexity and model latency.",
        "impact": "The MT models have significantly improved the model's ability to discern and learn from intricate patterns in high-cardinality data, leading to more accurate and generalizable predictions."
      },
      "deep_learning": {
        "description": "DoorDash transitioned from tree-based models to deep learning models to overcome performance plateaus and improve generalization to unseen or rare use cases. This shift has enhanced the model's ability to detect both high- and low-level signals and model complex feature interactions.",
        "impact": "The use of deep learning has allowed for more accurate, robust, and generalizable ETA predictions, addressing the limitations of tree-based models."
      },
      "probabilistic_models": {
        "description": "DoorDash employs a two-layer structure with a probabilistic prediction model as the base layer. This approach allows for a more nuanced understanding of uncertainty in delivery times by modeling the probability distribution of delivery times.",
        "impact": "The probabilistic model improves customer trust by providing more accurate and reliable ETA estimates that account for real-world uncertainties."
      }
    },
    "evaluation_metrics": {
      "calibration": {
        "description": "Calibration ensures that the predicted distributions align closely with actual outcomes. This is measured using the probability integral transform (PIT) histogram visualization, which compares predicted quantiles with actual delivery times.",
        "impact": "Calibration is crucial for ensuring that predictions are not only accurate for the most likely delivery time but also reliable and reflective of actual delivery scenarios."
      },
      "accuracy": {
        "description": "Accuracy is measured using the continuous ranked probability score (CRPS), which extends the concept of mean absolute error (MAE) to probabilistic forecasts. CRPS measures how well the predicted distribution aligns with the actual observed delivery time.",
        "impact": "CRPS provides a unified metric for comparing different models effectively, helping to identify areas where the model excels and where it needs refinement."
      }
    },
    "experiment_results": {
      "description": "DoorDash developed three versions of NextGen ETA models, all of which improved consumer outcomes. The models were evaluated based on accuracy (how often a delivery arrives on time) and consistency (ensuring ETAs are consistent and do not change drastically).",
