  "use_cases": [
    {
      "name": "Content Recommendation Model",
      "description": "This model powers both Airbnb’s Help Center search and the support content recommendation in Helpbot. It uses a pointwise ranking approach to determine the order of documents users receive. The model was transitioned from XLMRoBERTa to MT5 after incorporating prompts to transform the binary classification problem into a prompt-based language generation task. The generative model demonstrated significant improvements in relevance scores for support document ranking.",
      "model_used": "MT5",
      "impact": "Improved relevance of recommended documents, leading to better user experiences in the Help Center."
    },
    {
      "name": "Real-Time Agent Assistant Model",
      "description": "This model provides just-in-time guidance to customer support agents, helping them resolve user issues efficiently. It uses a mastermind Question-Answering (QA) model to answer intent-based questions such as whether a message is about cancellation or if a user is canceling due to a specific reason. The model leverages chat history and prompts to generate accurate responses.",
      "model_used": "t5-base, Narrativa",
      "impact": "Improved agent efficiency and consistency in responding to user queries, with a large engagement rate improvement in production."
    },
    {
      "name": "Paraphrase Model in Chatbot",
      "description": "This model improves chatbot engagement by paraphrasing user descriptions of their issues. It helps users feel understood and confirms that the chatbot is correctly interpreting their problem. The model was trained using a large dataset of agent-user conversations and was optimized to avoid generic responses.",
      "model_used": "T5",
      "impact": "Significantly improved chatbot engagement rates by providing more personalized and accurate paraphrasing of user inputs."
    }
  ],
  "technical_details": {
    "model_training": {
      "libraries_used": ["DeepSpeed"],
      "training_datasets": ["Annotation-based data", "Logging-based data"],
      "training_optimizations": "Combining annotation and logging datasets yielded the best performance. DeepSpeed was used to accelerate training from weeks to days."
    },
    "prompt_design": {
      "use": "Prompts were used to contextualize inputs and guide the model toward specific outputs, such as binary classification or intent detection.",
