        "used": false,
        "description": "Computer vision is not used in this system."
      },
      "robotics": {
        "used": false,
        "description": "Robotics is not used in this system."
      }
    },
    "ai_impact": {
      "efficiency": {
        "description": "The use of machine learning and NLP significantly improves the efficiency of merchant classification. The system processes ~2K net new merchants every day, with over 50% of the volume being categorized by in-house classifiers."
      },
      "accuracy": {
        "description": "The system maintains an overall error rate well below 5%, with probability thresholds set to ensure high precision in category predictions. The use of InferSent embeddings helps capture semantic meaning, improving classification accuracy."
      },
      "scalability": {
        "description": "The system is scalable due to the use of Airflow for orchestration, monthly model retraining, and the integration of Mechanical Turk for handling cases where models fail. This allows the system to handle a large volume of merchants efficiently."
      },
      "cost_reduction": {
        "description": "The use of Mechanical Turk provides a scalable and affordable workforce for tasks such as merchant identification and categorization when automated systems fail. This reduces the need for in-house resources for these tasks."
      },
      "user_experience": {
        "description": "The system improves the user experience by ensuring accurate and timely classification of merchants, which is crucial for the functionality of Brex's corporate card product. This contributes to the overall quality and reliability of the product."
      }
    }
  }
