{
  "ai_agent": {
    "name": "Strategy Factory AI Agent",
    "description": "A conversational AI agent designed to guide users through the setup and interpretation of Strategy Factory, making it more accessible to teams with varying levels of technical expertise.",
    "status": "In development"
  },
  "system_architecture": {
    "pipeline": "Airflow-based pipeline",
    "features": [
      "Flexible, end-to-end rule optimization",
      "User-configurable experiments through a simple interface",
      "Support for selecting event, feature set, time frame, and constraints"
    ],
    "backend": {
      "functions": ["Split", "FIT", "Squeeze", "Grow"],
      "output": ["Finalized rule set", "Monitoring estimates", "Auto Monitor UI integration"]
    }
  },
  "example_inputs_outputs": {
    "input": {
      "data": {
        "categories": ["Negative", "Positive", "Target"],
        "features": ["Fruit Type", "Color", "Sweetness", "Size"]
      },
      "requirements": {
        "recall": "100%",
        "original_rule": "Color == 'Red'"
      }
    },
    "output": {
      "optimized_rule": "(Color IN ['Red', 'Purple']) AND (Sweetness > 0.75)",
      "metrics": {
        "recall": "100%",
        "precision": "75%"
      }
    }
  },
  "adoption_highlights": {
    "domains": ["Login", "KYC", "Deposits", "Withdrawals"],
    "login_protection": {
      "investigation_time_reduction": "25%",
      "rule_improvement": "Improved coverage and precision"
    },
    "withdrawal_protection": {
      "rule_contribution": "Over a quarter of all risk detections",
      "system_lifting_standard_improvement": "60%"
    }
  },
  "roadmap": {
    "current_status": "In development",
    "future_features": [
      "Enhanced conversational AI agent for user guidance",
      "Further refinements to rule optimization techniques",
      "Expanded support for additional risk domains"
    ]
  },
  "key_components": {
    "split": {
      "description": "A single-path rule generation method that adds one condition at a time by picking the best option at each step.",
      "tradeoffs": [
        "Greedy path dependency",
        "Limited flexibility and coverage"
      ]
    },
    "fit": {
      "description": "A module designed to build a full set of complementary rules by looping through the Split process multiple times.",
      "features": [
        "Rule set generation",
        "Bagging for diversity",
        "Residual learning for coverage",
        "Decay iteration for flexibility"
      ]
    },
    "global_gain": {
      "description": "A customizable utility function that evaluates the marginal improvement each new rule brings to the overall rule set.",
      "features": [
        "Business-aware optimization",
        "Cross-label optimization",
        "Supports trade-offs between precision and recall"
      ]
    },
    "split_constraints": {
      "description": "A method for injecting domain knowledge and business requirements into the rule generation process.",
      "types": [
        "Sign constraints",
        "Threshold limits",
        "Mask system"
      ]
    },
    "squeeze_and_grow": {
      "description": "Tools for refining existing rules to better fit shifting business requirements or new data patterns.",
      "operations": [
        "Squeeze: Refines existing rule thresholds to optimize for better precision or recall",
        "Grow: Adds new conditions to a rule if doing so improves results"
      ]
    }
  }
}

