{
  "research_findings": {
    "model_performance": {
      "multilingual_instructional_pre_training": "Models trained with multilingual instructions perform significantly better across various tasks and languages compared to monolingual models or zero-shot baselines like GPT3.5 and GPT4.",
      "generalization_to_unseen_languages": "mEdIT models generalize well to languages not seen during training, especially when the underlying LLMs have been pre-trained on those languages.",
      "model_size_impact": "Larger models (e.g., 13B parameters) show significantly improved performance across all tasks, particularly for GEC and Paraphrasing.",
      "CLMs_outperform_seq2seq": "Causal language models (CLMs) outperform encoder-decoder models (Seq2Seq) in most cases, with performance increasing as model size increases."
    },
    "training_data_impact": {
      "data_quality_over_quantity": "Performance improvements are more closely correlated with data quality than quantity, as seen in the case of German, where a small dataset still led to significant improvements with fine-tuning.",
      "language_specific_performance": "Performance on edited languages is correlated with the availability and quality of training data for those languages. For example, Arabic had lower quality feedback due to lower-quality training data."
    },
    "human_feedback": {
      "positive_ratings": "Model outputs received high ratings across all languages, with the most positive feedback for English, German, Chinese, and Spanish.",
      "areas_for_improvement": "Performance for Arabic, Chinese, Japanese, Korean, and Spanish needs improvement, likely due to lower-quality training data or model limitations."
    }
