{
  "ai_use_cases": [
    {
      "use_case": "Candidate List Generation",
      "description": "An ML solution determines the most likely neighborhood where a user will place an order next, enabling the generation of highly localized candidate lists for OOA recommendations. This solution integrates signals from both Uber Eats and Uber apps over multiple-year time horizons and reduces these signals to a small set of ~10 features for scalability."
    },
    {
      "use_case": "First Pass Ranking",
      "description": "A low-cost scoring function is applied to filter and reduce the set of eligible candidate merchants based on criteria like unavailability and invalid deliverability. This helps conserve system bandwidth and reduce machine learning-related costs."
    },
    {
      "use_case": "Second Pass Ranking",
      "description": "A learning-to-rank (LTR) modeling framework is used to rank the small set of merchants retrieved from the first-pass ranking. This framework utilizes features such as user order history, in-app and out-of-app engagement, and merchant quality, reliability, and affordability. A lightweight feature set summarizing a user’s cuisine preferences is also used to encourage exploration of new cuisines and reduce online storage costs."
    },
    {
      "use_case": "Re-Ranking & Blending",
      "description": "A re-ranking and blending layer is introduced post the ML-based second-pass ranking to tailor recommendations toward different brand strategies and marketing priorities. This allows local marketing teams to define their own strategies flexibly with minimal work, using automated hierarchical configuration merge and override at different geographical region levels."
    }
  ],
  "ai_technologies": [
    {
      "technology": "ML Solution for Candidate List Generation",
      "description": "An ML solution that integrates high and low throughput signals from both Uber Eats and Uber apps over multiple-year time horizons to determine the most likely neighborhood where a user will place an order next."
    },
    {
      "technology": "Learning-to-Rank (LTR) Modeling Framework",
      "description": "A framework used in the second pass ranking to rank the small set of merchants retrieved from the first-pass ranking. This framework utilizes features such as user order history, in-app and out-of-app engagement, and merchant quality, reliability, and affordability."
    },
    {
      "technology": "Lightweight Feature Set for Cuisine Preferences",
      "description": "A lightweight feature set summarizing a user’s cuisine preferences across their entire Uber Eats history. This feature is updated daily with a Bayesian update logic and upweights recent orders to reflect the user’s recent behavioral changes."
    },
    {
      "technology": "Spectral Clustering for Cuisine Similarity Analysis",
      "description": "A technique used to quantify the similarity between cuisines by performing spectral clustering on a regularized cuisine co-occurrence matrix. This helps in grouping cuisines into natural clusters and provides an exploration lever for the recommendation system."
    },
    {
      "technology": "Automated Hierarchical Configuration Merge and Override",
      "description": "A mechanism that allows local marketing teams to define their own strategies flexibly with minimal work, using automated hierarchical configuration merge and override at different geographical region levels."
    }
  ],
  "ai_impact": [
    {
      "impact": "Improved Recommendation Relevancy",
      "description": "The use of ML solutions and lightweight feature sets has significantly improved the relevancy of recommendations by incorporating user metadata, cuisine preferences, and recent behavioral changes."
    },
    {
      "impact": "Increased User Engagement",
      "description": "The implementation of the second pass ranking system with a learning-to-rank (LTR) modeling framework and exploration lever has driven a 4% lift in email’s CTR in recent online experimentation."
    },
    {
      "impact": "Reduced System Costs",
      "description": "The use of lightweight feature sets and efficient embedding schemes has reduced online storage costs by 10x while maintaining the majority of the feature’s signal."
    },
    {
      "impact": "Enhanced Flexibility for Campaign Owners",
      "description": "The introduction of a re-ranking and blending layer has provided campaign owners with the flexibility to control candidate lists and tailor recommendations toward different brand strategies and marketing priorities."
    }
  ],
  "ai_challenges": [
    {
      "challenge": "Scalability of ML Solutions",
      "description": "Ensuring the scalability of ML solutions to the hundreds of millions of Uber users campaign owners communicate with required reducing signals to a small set of ~10 features."
    },
    {
      "challenge": "Availability of User-Centric Features",
      "description": "For new and churned users, user-centric features are often not available, requiring reliance on long-dated user signals to provide good recommendations."
    },
    {
      "challenge": "Geographic Constraints in Collaborative Recommendation Systems",
      "description": "Due to the geographic constraints of orders on Uber Eats, it can be difficult for collaborative recommendation system techniques to learn restaurant similarity."
    },
    {
      "challenge": "Cost-Efficient Storage and Use of Signals",
      "description": "Storing and using long-dated user signals in a cost-efficient manner is a challenge, requiring the construction of a lightweight feature set summarizing a user’s cuisine preferences."
    }
  ],
